solution.javascript:
import { test, expect } from '@playwright/test';

test('handle dynamic content', async ({ page }) => {
  await page.goto('https://practice.expandtesting.com/dynamic-loading/2');

  await page.click('button:has-text("Start")');

  // Wait for loading to finish and content to appear
  await page.waitForSelector('#finish', { state: 'visible', timeout: 10000 });

  const result = page.locator('#finish');
  await expect(result).toContainText('Hello World!');

  // Test dynamic table
  await page.goto('https://practice.expandtesting.com/tables');
  await page.waitForLoadState('networkidle');

  const tableRows = page.locator('table tbody tr');
  const rowCount = await tableRows.count();
  expect(rowCount).toBeGreaterThan(0);
});

